-- data/speciesBaseStats.lua - Pet Species Base Stats
-- Generated from wago.db BattlePetSpeciesState table
-- Formula: base = 8 + (modifier / 200)
-- State IDs: 19 = health, 18 = power, 20 = speed
-- DO NOT EDIT MANUALLY - Regenerate from DB2 when new pets are added
--
-- Regeneration query (MySQL, against wago.db):
--
--   SELECT CONCAT(
--       '    [', st.BattlePetSpeciesID, '] = {health = ',
--       TRIM(TRAILING '.' FROM TRIM(TRAILING '0' FROM FORMAT(8 + (COALESCE(MAX(CASE WHEN st.BattlePetStateID = 19 THEN st.Value END), 0) / 200.0), 1))),
--       ', power = ',
--       TRIM(TRAILING '.' FROM TRIM(TRAILING '0' FROM FORMAT(8 + (COALESCE(MAX(CASE WHEN st.BattlePetStateID = 18 THEN st.Value END), 0) / 200.0), 1))),
--       ', speed = ',
--       TRIM(TRAILING '.' FROM TRIM(TRAILING '0' FROM FORMAT(8 + (COALESCE(MAX(CASE WHEN st.BattlePetStateID = 20 THEN st.Value END), 0) / 200.0), 1))),
--       '},'
--   ) as baseStats
--   FROM BattlePetSpeciesState st
--   WHERE st.BattlePetStateID IN (18, 19, 20)
--   GROUP BY st.BattlePetSpeciesID
--   ORDER BY st.BattlePetSpeciesID;

